/**
 * The ServiceRequestRegistry is a centralized registry for managing service requests.
 * It allows services to register themselves and other services to discover available services.
 */

// Class definition
class ServiceRequestRegistry {
    private services: Map<string, Service>;

    constructor() {
        this.services = new Map();
    }

    // Method to register a service
    registerService(service: Service): void {
        this.services.set(service.id, service);
    }

    // Method to unregister a service
    unregisterService(serviceId: string): void {
        this.services.delete(serviceId);
    }

    // Method to get a service by its ID
    getService(serviceId: string): Service | null {
        return this.services.get(serviceId) || null;
    }

    // Method to list all registered services
    listServices(): Service[] {
        return Array.from(this.services.values());
    }
}
